const DATA={presets:[{id:'clean-proof-settlement',name:'Clean proof-settlement run',description:'Public-safe mandate with complete proof, replay, validation, challenge clearance, authority boundary, and Chronicle receipt.',values:{jobSpec:92,escrow:82,execution:84,proofBundle:91,replay:88,validatorQuorum:86,disputeClearance:78,authority:90,chronicle:84,risk:24,proofDebt:14}},{id:'no-proofbundle',name:'No ProofBundle',description:'The job produces output but no settlement-grade ProofBundle. Settlement is blocked.',values:{jobSpec:82,escrow:78,execution:80,proofBundle:12,replay:25,validatorQuorum:62,disputeClearance:66,authority:74,chronicle:20,risk:45,proofDebt:88}},{id:'unreplayable-run',name:'Unreplayable run',description:'The run appears useful but cannot be replayed from pinned inputs, artifacts, signatures, and validator records.',values:{jobSpec:88,escrow:80,execution:82,proofBundle:74,replay:18,validatorQuorum:76,disputeClearance:72,authority:82,chronicle:35,risk:55,proofDebt:74}},{id:'authority-gap',name:'Authority gap',description:'Evidence exists, but the authority boundary is not explicit enough for institutional settlement.',values:{jobSpec:86,escrow:72,execution:78,proofBundle:82,replay:80,validatorQuorum:78,disputeClearance:70,authority:22,chronicle:48,risk:62,proofDebt:58}},{id:'disputed-receipt',name:'Disputed receipt',description:'A challenge window catches validator pressure. The system holds settlement.',values:{jobSpec:84,escrow:80,execution:82,proofBundle:84,replay:79,validatorQuorum:42,disputeClearance:18,authority:80,chronicle:44,risk:66,proofDebt:63}}]};
const sliders=['jobSpec','escrow','execution','proofBundle','replay','validatorQuorum','disputeClearance','authority','chronicle','risk','proofDebt'];const stages=['REQUEST','ESCROW','EXECUTE','PROOF','VALIDATE','SETTLE','CHRONICLE'];const state={...DATA.presets[0].values,preset:'clean-proof-settlement'};const $=s=>document.querySelector(s);function clamp(x){return Math.max(0,Math.min(100,Number(x)||0));}function gates(){return [['JobSpec complete',state.jobSpec>=70],['Escrow posture bounded',state.escrow>=55],['Execution trace present',state.execution>=65],['ProofBundle complete',state.proofBundle>=70],['Replay path present',state.replay>=70],['Validator quorum clear',state.validatorQuorum>=70],['Dispute window clear',state.disputeClearance>=60],['Authority boundary explicit',state.authority>=70],['Risk bounded',state.risk<=55],['Proof debt low',state.proofDebt<=45],['Chronicle receipt ready',state.chronicle>=60]];}function readiness(){const g=gates();const score=g.filter(x=>x[1]).length/g.length;const weighted=(state.jobSpec+state.escrow+state.execution+state.proofBundle+state.replay+state.validatorQuorum+state.disputeClearance+state.authority+state.chronicle+(100-state.risk)+(100-state.proofDebt))/11;return Math.round((score*.62+weighted/100*.38)*100);}function verdict(){if(state.proofBundle<35)return 'NO_PROOFBUNDLE_NO_SETTLEMENT';if(state.replay<45)return 'NO_REPLAY_NO_SETTLEMENT';if(state.authority<45)return 'NO_AUTHORITY_NO_AUTONOMY';if(state.validatorQuorum<55||state.disputeClearance<45)return 'DISPUTE_WINDOW_HOLD';if(state.risk>70||state.proofDebt>70)return 'RETURN_TO_PROOF';if(readiness()>=82)return 'HUMAN_REVIEW_READY_TO_SETTLE';return 'SETTLEMENT_HELD_FOR_REVIEW';}function settlementWork(){return Math.round((state.jobSpec*state.execution*state.proofBundle*state.replay*state.validatorQuorum*state.disputeClearance*state.authority*state.chronicle)/1e14);}function liveStage(){const checks=[state.jobSpec,state.escrow,state.execution,state.proofBundle,state.validatorQuorum,state.disputeClearance,state.chronicle];let i=0;for(;i<checks.length;i++){if(checks[i]<65)break;}return Math.min(i,stages.length-1);}function render(){sliders.forEach(k=>{const el=$('#'+k);if(el){el.value=state[k];const out=$(`[data-out="${k}"]`);if(out)out.textContent=state[k];}});const rd=readiness(),vd=verdict(),sw=settlementWork();$('#readiness').textContent=rd;$('#settlementWork').textContent=sw;$('#verdict').textContent=vd.replaceAll('_',' ');$('#readinessMirror').textContent=rd+'/100';$('#orb').style.filter=`saturate(${.8+rd/120}) brightness(${.82+rd/180})`;$('#orb').style.transform=`scale(${.92+rd/800})`;renderStages();renderGates();renderLedger();$('#briefText').textContent=brief();document.querySelectorAll('.preset').forEach(p=>p.classList.toggle('active',p.dataset.id===state.preset));}function renderStages(){const box=$('#stages');box.innerHTML='';const active=liveStage();stages.forEach((s,i)=>{let cls='stage ';if(i<active)cls+='pass ';else if(i===active)cls+='active ';else cls+='hold ';const div=document.createElement('div');div.className=cls;div.innerHTML=`<div class="num">${String(i+1).padStart(2,'0')}</div><b>${s}</b><span>${stageText(s)}</span>`;box.appendChild(div);});}function stageText(s){return {REQUEST:'job spec + policy',ESCROW:'simulated budget rail',EXECUTE:'bounded work trace',PROOF:'ProofBundle emitted',VALIDATE:'replay + quorum',SETTLE:'human-review gate',CHRONICLE:'durable memory'}[s];}function renderGates(){const box=$('#gates');box.innerHTML='';gates().forEach(([label,pass])=>{const d=document.createElement('div');d.className='gate '+(pass?'pass':'fail');d.innerHTML=`<b>${pass?'PASS':'HOLD'}</b><span>${label}</span>`;box.appendChild(d);});}function renderLedger(){const rows=[['JobSpec',state.jobSpec,'request'],['ProofBundle',state.proofBundle,'proof'],['Replay',state.replay,'validate'],['Validator quorum',state.validatorQuorum,'validate'],['Authority',state.authority,'permission'],['Chronicle',state.chronicle,'memory']];const box=$('#ledger');box.innerHTML='';rows.forEach(([name,val,kind])=>{const pass=val>=60;const r=document.createElement('div');r.className='row';r.innerHTML=`<b>${name}</b><span>${kind} · signal ${val}/100</span><span class="status ${pass?'passText':'holdText'}">${pass?'cleared':'held'}</span>`;box.appendChild(r);});}function brief(){return `GoalOS Proof-Settlement Lifecycle\n\nLifecycle: Request → Escrow → Execute → Proof → Validate → Settle → Chronicle\nReadiness: ${readiness()}/100\nSettlement work index: ${settlementWork()}/100\nVerdict: ${verdict()}\n\nGates:\n${gates().map(([g,p])=>`- ${p?'PASS':'HOLD'} · ${g}`).join('\n')}\n\nBoundary: local public-safe simulation only. No wallet, no token route, no transaction, no factual certification, no production authority.`;}function exportReceipt(){const payload={receiptType:'GoalOSProofSettlementLifecycleReceipt',version:'v36-proof-settlement-lifecycle-console',generatedAt:new Date().toISOString(),lifecycle:stages,inputs:{...state},readiness:readiness(),settlementWork:settlementWork(),verdict:verdict(),gates:Object.fromEntries(gates()),posture:{browserLocal:true,zeroNetwork:true,noWallet:true,simulatedSettlementOnly:true,noUserDataWanted:true,noProductionAuthority:true}};const blob=new Blob([JSON.stringify(payload,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='goalos-proof-settlement-lifecycle-receipt.json';a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000);}async function copyBrief(){try{await navigator.clipboard.writeText(brief());$('#copyBrief').textContent='Copied';setTimeout(()=>$('#copyBrief').textContent='Copy review brief',1200)}catch{$('#copyBrief').textContent='Copy failed';setTimeout(()=>$('#copyBrief').textContent='Copy review brief',1200)}}function applyPreset(p){state.preset=p.id;Object.assign(state,p.values);render();}function inject(kind){state.preset='custom';if(kind==='proof'){state.proofBundle=8;state.replay=18;state.proofDebt=92;state.chronicle=15;}if(kind==='replay'){state.replay=10;state.validatorQuorum=Math.min(state.validatorQuorum,55);state.proofDebt=82;}if(kind==='authority'){state.authority=12;state.risk=78;state.disputeClearance=Math.min(state.disputeClearance,45);}render();}function init(){const pbox=$('#presets');DATA.presets.forEach(p=>{const b=document.createElement('button');b.className='preset';b.dataset.id=p.id;b.innerHTML=`<b>${p.name}</b><span>${p.description}</span>`;b.addEventListener('click',()=>applyPreset(p));pbox.appendChild(b);});sliders.forEach(k=>{const el=$('#'+k);if(el)el.addEventListener('input',()=>{state[k]=clamp(el.value);state.preset='custom';render();});});$('#cleanRun').addEventListener('click',()=>applyPreset(DATA.presets[0]));$('#breakProof').addEventListener('click',()=>inject('proof'));$('#breakReplay').addEventListener('click',()=>inject('replay'));$('#breakAuthority').addEventListener('click',()=>inject('authority'));$('#exportReceipt').addEventListener('click',exportReceipt);$('#copyBrief').addEventListener('click',copyBrief);render();}init();